-- ----------------------------
-- Table structure for ich_inheritance_story
-- ----------------------------
DROP TABLE IF EXISTS `ich_inheritance_story`;
CREATE TABLE `ich_inheritance_story`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标题',
  `region` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '所属区县：莲都区、龙泉市、青田县等',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '内容',
  `cover_image` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面图 URL',
  `create_time` datetime(6) NOT NULL,
  `inheritor_id` bigint NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1004 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '非遗传承故事表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of ich_inheritance_story
-- ----------------------------
INSERT INTO `ich_inheritance_story` VALUES (1, '徐朝兴：69载青瓷路，一生逐梦青如玉', '龙泉市', '在龙泉的群山之间，窑火千年不熄，淬炼出“青如玉、明如镜、声如磬”的龙泉青瓷，而徐朝兴，便是这片青瓷世界里，用一生践行匠心的守护者。作为国家级首批非遗传承人、中国工艺美术大师，他的69载制瓷生涯，不仅是个人与青瓷的深情相拥，更是一段跨越时代的非遗传承史诗，镌刻着坚守、创新与薪火相传的动人篇章。\n与青瓷的缘分，始于1956年那个寻常的春日。彼时13岁的徐朝兴，跟着父亲步行八十多里山路，来到龙泉陶瓷厂当学徒，师从著名青瓷艺人李怀德，从此叩开了青瓷艺术的大门。年少的他，没有丝毫懈怠，每天天不亮就起床，先把作坊打扫干净，再蹲在龙窑边，观察老师傅们拉坯、修坯、施釉、烧窑的每一个细节，默默记在心里，反复模仿练习。拉坯是青瓷制作的基础，看似简单的旋转与拿捏，却需要精准的力道与极致的耐心，初学时，他常常练到手臂酸痛难忍，指尖磨出密密麻麻的水泡，水泡破了又起，起了又破，最后结成厚厚的老茧，连指纹都被磨平，可他从未有过一句怨言。“做手艺，就得沉下心来，一步都不能偷工减料。”师傅的教诲，像一颗种子，在他心里生根发芽，成为他一生坚守的准则。\n\n1957年，浙江省启动仿古瓷研制工作，徐朝兴凭借过人的天赋和刻苦的态度，成为攻关小组里年龄最小的成员。这段经历，让他得以接触到龙泉青瓷的核心技艺，也让他深刻认识到，青瓷不仅是一种器物，更是一种承载着千年文化的载体。为了攻克仿古瓷的烧制难题，他常常守在窑边，不分昼夜地观察窑火的变化，记录每一次温度、气氛对瓷釉的影响，反复调试釉料配方，有时候一守就是一整天，饿了就啃几口干粮，困了就趴在窑边打个盹。有一次，为了烧制一件仿宋哥窑作品，他连续烧了七窑，都未能达到理想的开片效果，身边的人都劝他放弃，可他却咬着牙说：“青瓷是老祖宗传下来的宝贝，不能在我们这一代断了根。”凭着这份执着，他最终攻克了难关，烧制出的仿古瓷，形神兼备，足以以假乱真，也让他在青瓷界崭露头角。\n\n上世纪90年代，龙泉青瓷行业陷入低谷，市场萎缩，许多艺人纷纷转行，曾经热闹的瓷窑，渐渐变得冷清。看着一手培育自己的陶瓷厂日渐萧条，看着千年技艺面临失传的风险，徐朝兴心急如焚。此时，组织破格提拔他担任龙泉青瓷研究所所长，接过了传承与振兴龙泉青瓷的重任。为了保住核心技艺，他带领团队驻守研究所，一边整理青瓷烧制的传统技艺，抢救性记录老艺人的经验，一边积极探索创新，试图让青瓷适应现代市场的需求。他深知，传承不是墨守成规，创新才能让非遗焕发新生。经过无数次试验，他先后研发出哥弟绞胎、哥弟混合、象形开片、露胎装饰、青瓷玲珑等多种新工艺，打破了传统青瓷的装饰局限，让龙泉青瓷在保留传统韵味的同时，更具现代审美价值。其中，他的拿手绝活“跳刀”技艺，更是达到了炉火纯青的境界——制作一个菱口碗，里里外外要划上万刀，每一刀都要屏住呼吸，一气呵成，稍有失误，便前功尽弃。这份绝活，他修炼了六十余年，如今，他制作的跳刀纹饰，线条流畅、疏密有致，仿佛电脑刻制一般，令人惊叹。\n\n“第一要执着，第二要坚守，第三要传承。”这是徐朝兴常挂在嘴边的话，也是他一生的践行。如今，已经八十多岁的他，依然保持着每天清晨5点起床的习惯，利用清晨的黄金时间创作，无论寒冬酷暑，从未间断。他常戏称自己是“80后”，依旧精力充沛地奔波在青瓷传承的一线。为了让龙泉青瓷技艺薪火相传，他设立工作室，开展研讨授课活动100多场，毫无保留地分享自己的创作经验；多年来，他培养徒弟超过500人，其中3人获评中国工艺美术大师，8人成为正高级工艺美术师，3人担任博士生导师，还有数十人被评为省工艺美术大师，真正实现了“桃李满天下”。他还每年免费接纳数十名美院学子入驻工作室，亲自传授核心技艺，自掏腰包扶持青年创作者，为青瓷传承注入新鲜血液。\n\n2016年，为了更好地传播龙泉青瓷文化，徐朝兴带着徒弟在中国美术馆举办了为期半个月的“青瓷传承与复兴暨徐朝兴从艺60周年作品展”，展出了两百余件代表作，从青瓷的历史与发展脉络、烧制工具与材料，到烧制技艺与文献资料，全面展现了龙泉青瓷的魅力。他还自费出版了1.5万余册《青之梦，瓷之道——徐朝兴师徒精品集》，并非用于售卖，而是免费发放给热爱青瓷的人，只为让更多人认识龙泉青瓷、了解青瓷文化。如今，八十多岁的他，依然积极参加各类青瓷文化活动，不遗余力地推介龙泉青瓷，让这门千年技艺走出丽水、走向全国、走向世界。\n\n69载风雨兼程，69载匠心坚守。徐朝兴用一双磨平指纹的手，捏塑出一件件精美的青瓷作品，也捏塑出一段非遗传承的传奇。他的故事，是对“匠心”二字最生动的诠释，更是对非遗传承最有力的践行——唯有执着坚守，方能守住根脉；唯有勇于创新，方能续写辉煌。', '', '2026-03-01 00:00:00.000000', NULL);
INSERT INTO `ich_inheritance_story` VALUES (2, '章金麟：七旬翁守千年狮龙，让唐韵非遗重焕生机', '莲都区', '在莲都区海潮村，每逢春节，锣鼓喧天，五头火红的雄狮在绳索牵引下翻滚扑球、口喷焰火，九节龙灯蜿蜒起舞，照亮整个村落，欢呼声、喝彩声此起彼伏，这热闹的场景，是72岁的章金麟用七年时间，为家乡找回的千年文脉。作为海潮线拉狮子、九节龙灯两项区级非遗的传承人，他用一把竹刀、一卷铁丝、一份执念，复活了沉寂三十余年的唐代狮龙，让“狮龙之村”的荣耀，在新时代重新绽放光芒。\n海潮村，被誉为丽水最早创世的狮龙之村，线拉狮子与九节龙灯两项非遗项目，相传始创于唐代，迄今已逾千年。在过去，每到春节，狮龙巡游是村里最隆重的活动，村民们扶老携幼，争相观看，狮龙所到之处，寓意着吉祥如意、国泰民安。可随着时代的变迁，年轻人纷纷外出务工，老艺人相继离世，线拉狮子的表演，在上世纪90年代便戛然而止，九节龙灯也渐渐被遗忘，那些曾经威风凛凛的龙狮骨架，被随意堆放在角落，在风雨侵蚀和虫蛀下，渐渐腐朽，成为一段被尘封的记忆。\n\n2017年，退休后的章金麟回到海潮村，看到村里的年轻人几乎不知道“狮龙之村”的历史，看到老龙骨在角落默默蒙尘，心里像被针扎一样难受。“龙和狮子是我们村的魂，不能就这么没了。”怀着这份执念，他下定决心，要让九节龙灯重新回到村里，让千年狮龙文化重焕生机。可复原之路，远比想象中艰难。没有完整的图纸，没有现成的模具，只能凭着自己小时候的记忆，以及村里几位老人的零星回忆，一点点摸索。他先从寻找老龙骨开始，在村里的杂物间、祠堂角落，翻找那些残存的竹制龙骨，一点点拼凑，还原龙灯的结构和模样。\n\n为了复刻九节龙灯，章金麟几乎投入了全部的时间和精力。他每天泡在自己的小作坊里，切割竹片、打磨骨架、糊纸、上色，每一个环节都亲力亲为。龙灯的龙头，是整个作品的灵魂，需要精准把握比例和神态，他反复修改，光是龙头的草图，就画了几十张，直到满意为止。为了让龙灯更耐用、更威风，他放弃了传统的毛竹骨架，改用更坚固的钢丝，轿子也从木架换成铁架，但他始终坚持“样子不能变、结构不能变，不然非遗文化就全变味了”。经过几个月的辛苦劳作，第一盏九节龙灯终于复刻完成，当龙灯在村晚舞台上亮相时，村里的老人们激动得热泪盈眶，纷纷感慨：“龙回来了，我们村的魂也回来了。”\n\n九节龙灯的成功复刻，让章金麟更加坚定了传承的决心，但村里老人们的一句话，又让他陷入了新的思考：“龙做出来了，那狮子呢？还有没有人记得它？”线拉狮子，是海潮村另一项珍贵的非遗，其表演方式独特，通过绳索牵引狮头，让狮子做出翻滚、扑球、跳跃等动作，极具观赏性，相传是唐代宫廷技艺流传民间的产物。可线拉狮子已经沉寂了三十余年，没有任何实物留存，甚至连完整的记忆都寥寥无几，复原的难度，比复刻龙灯大了不止一倍。\n\n没有图纸，没有参照物，章金麟就凭着自己模糊的记忆，一点点画草图，一遍遍推翻重来。他回忆着小时候看到的狮子模样，琢磨着狮子的关节结构、牵引方式，前前后后，光是图纸就画了一个多月，一张张图纸上，铅笔线条层层叠叠，各个部位的尺寸标注得清晰明了，每一笔都凝聚着他的心血。图纸定稿后，新的难题又出现了——丽水本地没有肯接单制作狮头骨架的匠人，他四处打听，终于得知永康有专门的厂家可以定制，于是，他不顾年迈，一次次往返于海潮村和永康之间，车程近三个小时，每次都要坐最早的班车出发，最晚的班车回来，累得腰酸背痛，却从未抱怨过。他还自掏腰包，购买钢丝、布料、颜料等材料，前后花费了上万元，对于一位退休老人来说，这是一笔不小的开支，但他却说：“只要能让狮子回来，花再多钱也值得。”\n\n在狮子制作的过程中，章金麟全程跟进，每天和厂家沟通细节，修改设计，生怕出现一丝偏差。终于，在2023年海潮村村晚开始前的第十三天，五头线拉狮子正式运回村里。当狮子被抬进文化礼堂的那一刻，全村人都沸腾了，孩子们围着狮子欢呼雀跃，老人们抚摸着狮身，眼里满是欣慰。章金麟的孙子章晟浩，当时刚上高一，挤在人堆里，第一次见到这头传说中的狮子，他说：“之前爷爷画图纸、跑工厂，我其实没有太大感觉，但狮子运回来那一刻，特别震撼，我突然意识到，我们这一代人差点就看不到村里的这段文化历史。”\n\n狮子回来了，可如何让它“活”起来，又是一个难题。线拉狮子的表演，需要多人配合，通过绳索牵引狮头，掌握力度和节奏，才能让狮子做出各种灵动的动作。章金麟动员村里舞龙队的娘子军来学习舞狮，狮头一个就有十几斤重，拉一会儿就满头大汗，尤其是在冬天，娘子军们每天下班就赶来练习，练到全身湿透，手上磨出茧子，却没有一个人退缩。章金麟耐心地指导她们，讲解牵引的技巧，纠正她们的动作，一点点打磨，一遍遍练习，从最初的生硬卡顿，到后来的灵活自如，狮子在她们手里，渐渐学会了前后摆动、翻滚扑球，甚至还能翻个跟斗。\n\n2024年春节，久别的线拉狮子与九节龙灯终于同台展演，锣鼓喧天，狮舞龙腾，台下的手机屏连成一片星河，村民们的欢呼声此起彼伏。看着这热闹的场景，章金麟笑着说：“最有成就感的，就是一台村晚办下来，大家看着都满意了，我就开心了。”如今，每年春节，海潮村的狮龙巡游都成为莲都区的特色活动，吸引着周边村民前来观看，线拉狮子和九节龙灯，不仅成为海潮村的文化符号，更成为莲都非遗传承的生动缩影。\n\n章金麟知道，他抢在记忆彻底消散前拽住的那根绳索，需要更多双手来共同牵引。他开始主动教村里的年轻人制作龙灯、舞狮，把自己的技艺毫无保留地传授给他们，希望能有更多年轻人接过传承的接力棒。“我年纪大了，能做的不多，但我希望，这狮龙文化，能在村里一代代传下去，让我们的子孙后代，都能记住我们海潮村的根，记住这千年的唐韵非遗。”七旬老人的话语，朴实而坚定，他用自己的坚守，为非遗传承撑起了一片天，让千年狮龙，在新时代续写新的传奇。', '', '2026-03-01 00:00:00.000000', NULL);
INSERT INTO `ich_inheritance_story` VALUES (3, '蓝仙兰、蓝延蓝、蓝余根：畲寨三杰，让畲族文化代代相传', '景宁畲族自治县', '在景宁畲族自治县鹤溪街道东弄村，这座仅有420人口的畲族村落，却孕育出三位国家级非遗传承人——蓝仙兰（畲族三月三）、蓝延蓝（畲族彩带编织）、蓝余根（畲族传统婚俗），成为名副其实的“非遗活态博物馆”。在这里，织机声、山歌声、龙角声交织在一起，三位传承人用一生的坚守，守护着畲族千年的文化根脉，让畲乡的烟火气，在非遗传承中愈发浓郁。\n蓝仙兰，是“畲族三月三”的国家级传承人，与这一畲族最盛大的传统节日，相伴了四十余年。在她的记忆里，小时候的三月三，是畲寨最热闹的日子，家家户户都会做乌米饭、织彩带、唱山歌，男女老少身着畲族盛装，聚集在村口的晒谷场，对歌、跳舞、赶圩，欢声笑语传遍整个山谷。“三月三是我们畲族人的节日，是刻在骨子里的乡愁，是连接畲族儿女的纽带。”蓝仙兰说，正是这份对节日的热爱，让她走上了传承之路。\n\n年少时，蓝仙兰就跟着母亲学唱畲歌、织彩带，母亲的歌声悠扬婉转，指尖翻飞间，一根根彩线就变成了精美的彩带，这些场景，深深印在她的心里。长大后，她成了村里的文艺骨干，无论村里有什么活动，她都会带头唱畲歌、跳畲舞，把三月三的习俗传递给身边的人。可随着时代的发展，村里的年轻人纷纷外出务工，畲歌没人唱了，彩带没人织了，三月三的热闹，渐渐变得冷清，甚至有很多年轻的畲族儿女，不知道三月三的来历和习俗。看着畲族文化渐渐被遗忘，蓝仙兰心里十分着急，她暗下决心，一定要守住这份文化遗产，让三月三重新热闹起来。\n\n为了让畲族三月三习俗得以传承，蓝仙兰开始挨家挨户动员村民，尤其是年轻人，参与到三月三的活动中来。一开始，很多村民不理解，觉得唱畲歌、织彩带不能当饭吃，还有的年轻人觉得这些习俗太老旧，不愿意参与。蓝仙兰没有放弃，她耐心地给村民们讲解畲族文化的意义，手把手地教年轻人唱畲歌、织彩带，还自己掏钱购买材料，免费举办培训班。她还走进学校，在红星小学等学校开设畲歌、彩带编织课程，教孩子们传承畲族文化，一教就是五六年。“只要有人愿意学，我就愿意教，哪怕只有一个人，我也要把这份技艺传下去。”蓝仙兰说。\n\n四十多年来，蓝仙兰参与了近2000场“畲族三月三”相关的活动，其中包括18场国家级、省级大型文化宣传和展演活动，她的歌声，传遍了畲乡的山山水水，也让更多人了解了畲族三月三的习俗。她还带领村民们，把三月三的习俗与文旅融合，打造沉浸式的民俗体验活动，让游客们亲身感受畲族的山歌、彩带、乌米饭制作等特色文化，不仅让三月三成为景宁的文旅招牌，更带动了畲寨的旅游发展和村民增收。如今，每到三月三，东弄村都会热闹非凡，身着畲族盛装的村民们，唱山歌、跳畲舞、织彩带、做乌米饭，年轻人们主动参与，孩子们欢声笑语，畲族三月三的习俗，在蓝仙兰的坚守下，重新焕发了生机与活力。\n\n与蓝仙兰一样，蓝延蓝也是一位坚守畲族文化的传承人，她是畲族彩带编织技艺的国家级传承人，六岁起便跟随外婆学习织彩带，一织就是几十年，用一双巧手，编织出了畲族千年的“山哈梦”。畲族彩带，是畲族文化的重要载体，每一根彩带，都承载着畲族人民的情感与祝福，上面的图案，有畲族的图腾、山水、花鸟，还有吉祥如意的寓意，是畲族儿女传递情感的重要方式。\n\n小时候，蓝延蓝就看着外婆坐在织机前，指尖翻飞，一根根彩线在织机上穿梭，渐渐变成精美的彩带。她好奇地凑在旁边，跟着外婆学习，从穿线、打结，到编织图案，每一个环节，她都学得格外认真。外婆告诉她，畲族彩带是老祖宗传下来的宝贝，每一根彩带，都要用心去织，不能有丝毫马虎。这句话，蓝延蓝一直记在心里，几十年来，她始终坚守着纯手工编织的技艺，用心对待每一件作品。\n\n随着时代的发展，传统彩带的样式和用途，渐渐不能满足现代人们的需求，很多年轻人觉得彩带不够时尚，不愿意学习编织技艺。蓝延蓝意识到，传承不是墨守成规，只有创新，才能让彩带编织技艺焕发新生。于是，她开始尝试在传统彩带的基础上进行创新，将汉字与畲族传统图案相结合，编织出具有现代意蕴的彩带作品。其中，最具代表性的，就是一条长4米多、织有全国56个民族名称的“彩带王”，这条彩带，耗时数月，每一个字、每一个图案，都编织得精美绝伦，成为畲乡的文化传奇，不仅展现了畲族彩带的编织技艺，更传递了各民族团结一心的美好寓意。\n\n为了让彩带编织技艺薪火相传，蓝延蓝创办了畲族彩带工作室，坚持免费向村民和游客传授编织技巧，推动彩带技艺进校园、进社区。多年来，她带出了十四五名徒弟，已有上万名学员来工作室体验彩带编织，她编织的彩带，还远销美国、德国等多个国家，让畲族彩带走向了世界。“国家级非遗传承人称号，既是对我的肯定，更是激励。”蓝延蓝说，“我会接续传承创新，让老手艺焕发新活力，让更多人了解畲族彩带，爱上畲族文化。”\n\n在东弄村，还有一位值得铭记的传承人，他就是畲族传统婚俗的国家级传承人蓝余根。蓝余根出身赤郎世家，赤郎是畲族传统婚俗中的核心角色，负责主持婚礼、唱赤郎歌、完成各种婚俗仪式，是畲族婚俗文化的重要传承者。他从小就跟着长辈学习畲族婚俗，熟谙每一道婚俗流程，从提亲、定亲，到迎亲、拜堂，每一个环节的仪式、歌曲，他都烂熟于心。\n\n畲族传统婚俗，仪式繁琐、内涵丰富，蕴含着畲族人民的生活智慧和文化底蕴，是畲族文化的重要组成部分。可随着时代的变迁，很多年轻的畲族情侣，更倾向于举办现代婚礼，传统婚俗渐渐被遗忘，很多年轻一代，已经不知道畲族传统婚俗的流程和意义。蓝余根看在眼里，急在心里，他决心要复原传统畲族婚俗，让这一珍贵的文化遗产得以传承。\n\n为了复原传统婚俗，蓝余根走访了村里的老艺人，收集整理婚俗仪式、赤郎歌谱，一点点还原每一个环节的细节，还培育了10余名精通赤郎歌的传人，手把手地教他们唱赤郎歌、主持婚俗仪式。耄耋之年的他，依然坚持接待文化探访者，向远道而来的宾客展现畲族传统婚俗的原生魅力，用自己的方式，守护着畲族婚俗文化的根脉。虽然蓝余根已经离世，但他传承的畲族传统婚俗，并没有就此消失，他的徒弟们，继续坚守在传承一线，将畲族婚俗与文旅融合，打造沉浸式的民俗演艺，让更多人感受到畲族婚俗的独特魅力。\n\n织机声里藏文脉，山歌声中传乡愁。蓝仙兰、蓝延蓝、蓝余根，三位传承人，用一生的坚守，守护着畲族的文化根脉，他们的故事，是畲族文化传承的生动缩影，也是丽水非遗传承的动人篇章。在东弄村，在景宁的每一个畲寨，畲族文化正以活态传承的方式，在新时代绽放新芽，成为乡村振兴的文化动力。', '', '2026-03-01 00:00:00.000000', NULL);

SET FOREIGN_KEY_CHECKS = 1;
